```typescript
import { Platform } from 'react-native';
import OneSignal from 'react-native-onesignal';
import { ONESIGNAL_APP_ID } from './api';

export const initializeOneSignal = () => {
  if (!ONESIGNAL_APP_ID) {
    console.warn('OneSignal App ID not configured');
    return;
  }

  // Initialize OneSignal
  OneSignal.initialize(ONESIGNAL_APP_ID);

  // Request permission (iOS will show prompt, Android 13+ will show prompt)
  OneSignal.Notifications.requestPermission(true);

  // Setup notification handlers
  OneSignal.Notifications.addEventListener('click', (event) => {
    console.log('OneSignal: notification clicked:', event);
    // Handle notification click - navigate to article if data contains article_id
    const data = event.notification.additionalData;
    if (data?.article_id) {
      // Navigation logic here
    }
  });

  OneSignal.Notifications.addEventListener('foregroundWillDisplay', (event) => {
    console.log('OneSignal: notification will display in foreground:', event);
    // Can prevent display or modify notification
    event.preventDefault();
    event.notification.display();
  });
};

export const subscribeToNotifications = (subscribe: boolean) => {
  OneSignal.User.pushSubscription.optIn();
  if (!subscribe) {
    OneSignal.User.pushSubscription.optOut();
  }
};

export const getNotificationPermissionStatus = async (): Promise<boolean> => {
  return OneSignal.Notifications.getPermissionAsync();
};

export const setExternalUserId = (userId: string) => {
  OneSignal.login(userId);
};

export const removeExternalUserId = () => {
  OneSignal.logout();
};

// Tag users for segmentation
export const addTags = (tags: Record<string, string>) => {
  OneSignal.User.addTags(tags);
};
```

